RISK_COLOUR = {
    "LOW"    : "#16A34A",
    "MEDIUM" : "#F59E0B",
    "HIGH"   : "#DC2626",
}

def risk_tier(prob, thresh):
    """Convert raw probability into a three-tier risk band."""
    if prob < thresh * 0.6:
        return "LOW"
    elif prob < thresh:
        return "MEDIUM"
    else:
        return "HIGH"

def gauge_svg(probability: float, thresh: float = 0.5) -> str:
    """
    Render an SVG arc gauge showing default probability 0–100%.
    The needle sweeps from left (0%) to right (100%).
    Colour transitions: green → amber → red.
    """
    if probability > 1.0:
        pct = min(max(probability / 100.0, 0.0), 1.0)
    else:
        pct = min(max(probability, 0.0), 1.0)

    tier = risk_tier(pct, thresh)
    dynamic_color = RISK_COLOUR[tier]
    angle = -180 + pct * 180          # sweep from -180° to 0°
    rad   = np.radians(angle)
    cx, cy, r = 130, 115, 90

    # Needle tip coordinates
    nx = cx + r * np.cos(rad)
    ny = cy + r * np.sin(rad)

    # Arc segments: green (0–40%), amber (40–70%), red (70–100%)
    def arc_d(start_deg, end_deg, radius):
        s = np.radians(start_deg); e = np.radians(end_deg)
        x1, y1 = cx + radius * np.cos(s), cy + radius * np.sin(s)
        x2, y2 = cx + radius * np.cos(e), cy + radius * np.sin(e)
        return f"M {x1:.1f} {y1:.1f} A {radius} {radius} 0 0 1 {x2:.1f} {y2:.1f}"

    svg = f"""
    <svg width="260" height="140" viewBox="0 0 260 140" xmlns="http://www.w3.org/2000/svg">
      <!-- Track -->
      <path d="{arc_d(-180,-1,90)}"  stroke="#E2E8F0" stroke-width="16" fill="none" stroke-linecap="round"/>
      <!-- Green zone 0-40% -->
      <path d="{arc_d(-180,-108,90)}" stroke="#16A34A" stroke-width="16" fill="none" stroke-linecap="round"/>
      <!-- Amber zone 40-70% -->
      <path d="{arc_d(-108,-54,90)}"  stroke="#F59E0B" stroke-width="16" fill="none" stroke-linecap="round"/>
      <!-- Red zone 70-100% -->
      <path d="{arc_d(-54,-1,90)}"    stroke="#DC2626" stroke-width="16" fill="none" stroke-linecap="round"/>
      <!-- Needle -->
      <line x1="{cx}" y1="{cy}"
            x2="{nx:.1f}" y2="{ny:.1f}"
            stroke="#0D1B2A" stroke-width="3" stroke-linecap="round"/>
      <circle cx="{cx}" cy="{cy}" r="6" fill="#0D1B2A"/>
      <!-- Labels -->
      <text x="30"  y="132" font-size="10" fill="#64748B" font-family="Inter,sans-serif">0%</text>
      <text x="115" y="20"  font-size="10" fill="#64748B" font-family="Inter,sans-serif" text-anchor="middle">50%</text>
      <text x="218" y="132" font-size="10" fill="#64748B" font-family="Inter,sans-serif">100%</text>
      <!-- Central probability display -->
      <text x="{cx}" y="{cy+35}" font-size="22" font-weight="700"
            fill="#0D1B2A" font-family="JetBrains Mono,monospace" text-anchor="middle">
        {pct*100:.1f}%
      </text>
      <text x="{cx}" y="{cy+50}" font-size="9" fill="#64748B"
            font-family="Inter,sans-serif" text-anchor="middle">DEFAULT PROBABILITY</text>
    </svg>"""
    return svg

def section(label, pill=None):
    """Render a styled section header."""
    pill_html = f'<span class="section-pill">{pill}</span>' if pill else ''
    st.markdown(
        f'<div class="section-header">{pill_html}<h2>{label}</h2></div>',
        unsafe_allow_html=True
    )

def df_to_html(df: pd.DataFrame, float_cols=None) -> str:
    """
    Convert a DataFrame to a styled HTML table with zero PyArrow dependency.
    Safe to pass to st.markdown(unsafe_allow_html=True).
    """
    float_cols = float_cols or []
    header = "".join(
        f'<th style="background:#1B6CA8;color:#fff;padding:8px 12px;'
        f'text-align:left;font-size:0.8rem;letter-spacing:0.04em;white-space:nowrap;">{c}</th>'
        for c in df.columns
    )
    rows_html = ""
    for i, (_, row) in enumerate(df.iterrows()):
        bg = "#F8FAFC" if i % 2 == 0 else "#FFFFFF"
        cells = ""
        for col in df.columns:
            val = row[col]
            if col in float_cols and isinstance(val, float):
                val = f"{val:.4f}"
            cells += (
                f'<td style="padding:7px 12px;font-size:0.82rem;'
                f'border-bottom:1px solid #E2E8F0;">{val}</td>'
            )
        rows_html += f'<tr style="background:{bg};">{cells}</tr>'
    return (
        '<div style="overflow-x:auto;border-radius:8px;'
        'box-shadow:0 1px 4px rgba(0,0,0,0.08);margin:0.5rem 0 1rem;">'
        f'<table style="border-collapse:collapse;width:100%;font-family:Inter,sans-serif;">'
        f'<thead><tr>{header}</tr></thead>'
        f'<tbody>{rows_html}</tbody></table></div>'
    )

def metric_card(label, value, sub="", risk_class=""):
    """Render a styled KPI card."""
    val_class = ""
    if risk_class == "risk-high":  val_class = "crimson"
    if risk_class == "risk-low":   val_class = "emerald"
    st.markdown(f"""
    <div class="metric-card {risk_class}">
        <div class="metric-label">{label}</div>
        <div class="metric-value {val_class}">{value}</div>
        <div class="metric-sub">{sub}</div>
    </div>""", unsafe_allow_html=True)

