@st.cache_resource(show_spinner="Loading models…")
def load_models():
    """
    Load serialised model pipelines and metadata from notebook artefacts.
    Expects files in the same directory as dashboard.py (relative paths).
    Returns None values if artefacts are missing — triggers demo mode.
    """
    xgb_model, lr_model, meta, comparison_df = None, None, {}, None

    try:
        if os.path.exists("best_xgb_pipeline.pkl"):
            xgb_model = joblib.load("best_xgb_pipeline.pkl")
    except Exception:
        xgb_model = None

    try:
        if os.path.exists("best_lr_pipeline.pkl"):
            lr_model = joblib.load("best_lr_pipeline.pkl")
    except Exception:
        lr_model = None

    try:
        if os.path.exists("feature_metadata.json"):
            with open("feature_metadata.json") as f:
                meta = json.load(f)
    except Exception:
        meta = {}

    try:
        if os.path.exists("model_comparison_results.csv"):
            comparison_df = pd.read_csv("model_comparison_results.csv")
    except Exception:
        comparison_df = None

    return xgb_model, lr_model, meta, comparison_df

xgb_model, lr_model, meta, comparison_df = load_models()

