    # ── Baseline borrower ────────────────────────────────────────────────────
    st.markdown("**Baseline Borrower (all other features held constant)**")
    bc1, bc2, bc3, bc4 = st.columns(4)
    base_credit = bc1.number_input("Credit Score", 300, 850, 650, key="sc_cs")
    base_income = bc2.number_input("Income (KES)", 50_000, 5_000_000, 600_000,
                                    step=50_000, key="sc_inc")
    base_loan   = bc3.number_input("Loan Amount (KES)", 50_000, 20_000_000,
                                    1_500_000, step=50_000, key="sc_loan")
    base_age    = bc4.number_input("Age", 18, 80, 35, key="sc_age")

    # ── Generate risk surface ────────────────────────────────────────────────
    FEATURE_RANGES = {
        "Credit Score"     : (300,  850),
        "Annual Income"    : (50_000, 3_000_000),
        "Loan Amount"      : (50_000, 10_000_000),
        "Years Experience" : (0, 40),
        "Age"              : (18, 75),
    }
    BASE_VALUES = {
        "Credit Score"     : base_credit,
        "Annual Income"    : base_income,
        "Loan Amount"      : base_loan,
        "Years Experience" : 8,
        "Age"              : base_age,
    }

    grid_n  = 40
    x_range = np.linspace(*FEATURE_RANGES[x_axis], grid_n)
    y_range = np.linspace(*FEATURE_RANGES[y_axis], grid_n)
    XX, YY  = np.meshgrid(x_range, y_range)

    # Compute heuristic risk surface (or model surface if loaded)
    def heuristic_prob(credit, income, loan, age=35, exp=8):
        """Approximate default probability heuristic for demo mode."""
        score_norm = (credit - 300) / 550
        dti        = loan / max(income, 1)
        age_factor = abs(age - 38) / 40
        return float(np.clip(
            0.75 - score_norm * 0.55 + dti * 0.15 + age_factor * 0.05, 0.02, 0.97
        ))

    ZZ = np.zeros_like(XX)
    for i in range(grid_n):
        for j in range(grid_n):
            vals = dict(BASE_VALUES)
            vals[x_axis] = XX[i, j]
            vals[y_axis] = YY[i, j]
            ZZ[i, j] = heuristic_prob(
                vals["Credit Score"], vals["Annual Income"],
                vals["Loan Amount"],  vals.get("Age", base_age),
                vals.get("Years Experience", 8)
            )

    # ── Plot ─────────────────────────────────────────────────────────────────
    fig4, ax4 = plt.subplots(figsize=(9, 6))
    cf = ax4.contourf(XX, YY, ZZ, levels=25, cmap="RdYlGn_r", alpha=0.92)
    plt.colorbar(cf, ax=ax4, label="Default Probability")

    # Threshold boundary
    cs = ax4.contour(XX, YY, ZZ, levels=[threshold],
                     colors="black", linewidths=2.0, linestyles="--")
    ax4.clabel(cs, fmt=f"Threshold = {threshold:.2f}", fontsize=9)

    # Mark baseline borrower
    ax4.scatter([BASE_VALUES[x_axis]], [BASE_VALUES[y_axis]],
                c="white", s=120, zorder=5, edgecolors="black",
                linewidths=2, label="Baseline borrower")
    ax4.legend(fontsize=9)

    ax4.set_xlabel(x_axis, fontsize=10)
    ax4.set_ylabel(y_axis, fontsize=10)
    ax4.set_title(f"Risk Landscape: {x_axis} vs {y_axis}\n"
                  f"Dashed line = approval threshold ({threshold:.2f})",
                  fontweight="bold")
    ax4.set_facecolor("#F1F5F9")
    fig4.patch.set_facecolor("#F1F5F9")
    plt.tight_layout()
    st.pyplot(fig4)
    plt.close(fig4)

    st.markdown("""
    <div class="info-box">
    🟢 <strong>Green zones</strong> — below threshold: approve  &nbsp;|&nbsp;
    🔴 <strong>Red zones</strong> — above threshold: decline or restructure  &nbsp;|&nbsp;
    ⚫ <strong>Dashed line</strong> — current approval boundary
    </div>""", unsafe_allow_html=True)

